export default defineApi({
  name: "List Posts",
  directory: "public",
  method: "GET",
  roles: [],
  caching: { ttl: 30 },   // cache successful responses for 30s
  responses: { 200: z.object({ data: z.array(PostSchema) }) },
  handler: async () => ({ status: 200, data: await posts.all() }),
});

import { memoryCache, redisCache, kvCache, tryCache } from "@hushkey/howl/api/cache";

memoryCache({ maxSize: 1000 });
redisCache(redis);
kvCache(await Deno.openKv());
tryCache(memoryCache(), redisCache(redis), { timeoutMs: 300 });

defineConfig<State, Role>({
  roles,
  cache: tryCache(memoryCache(), redisCache(r)), // fast local, shared fallback
  rateLimitCache: redisCache(r),                  // counters — must be shared
});

